# -*- coding: utf-8 -*-
import io, re
PATH = r"C:\Users\82102\Desktop\kstarmap\map.html"
s = io.open(PATH,"r",encoding="utf-8").read()
changes = []

# 1) 메뉴에 웃음창고 추가
old_menu = "item('\U0001f4da', '\ud55c\ub958\uc815\ubcf4\ucc3d\uace0', \"document.getElementById('moreSheet').remove();openBoard()\")"
new_menu = (old_menu + " +\n"
"      item('\U0001f602', '\ud55c\ub958 \uc6c3\uc74c\ucc3d\uace0', \"document.getElementById('moreSheet').remove();openFunBoard()\")")
if old_menu in s and "openFunBoard" not in s:
    s=s.replace(old_menu,new_menu); changes.append("menu")
else:
    changes.append("menu skip")

# 2) openFunBoard 함수 삽입
anchor = "window.openBoard = async function() {"
if "openFunBoard" not in s and anchor in s:
    func = "// \u2500\u2500 \ud55c\ub958 \uc6c3\uc74c\ucc3d\uace0 \u2500\u2500\nwindow.openFunBoard = async function() {\n  const old = document.getElementById('funBoardSheet');\n  if (old) old.remove();\n  const sheet = document.createElement('div');\n  sheet.id = 'funBoardSheet';\n  sheet.style.cssText = 'position:fixed;inset:0;z-index:9999;display:flex;justify-content:center;background:rgba(0,0,0,0.3)';\n  const inner = document.createElement('div');\n  inner.style.cssText = 'background:var(--bg);display:flex;flex-direction:column;width:100%;max-width:620px;height:100%;';\n  sheet.appendChild(inner);\n  document.body.appendChild(sheet);\n  inner.innerHTML =\n    '<div style=\"display:flex;align-items:center;gap:10px;padding:14px 16px;border-bottom:1px solid var(--border)\">' +\n      '<button onclick=\"document.getElementById(\\'funBoardSheet\\').remove()\" style=\"background:var(--bg2);border:1px solid var(--border);border-radius:9px;width:36px;height:36px;font-size:18px;cursor:pointer\">\u2190</button>' +\n      '<div style=\"font-size:16px;font-weight:800;flex:1\">\U0001f602 \ud55c\ub958 \uc6c3\uc74c\ucc3d\uace0</div>' +\n      '<button onclick=\"openFunBoardWrite()\" style=\"background:var(--gold);color:#fff;border:none;border-radius:9px;padding:8px 14px;font-size:13px;font-weight:700;cursor:pointer\">\uae00\uc4f0\uae30</button>' +\n    '</div>' +\n    '<div id=\"funBoardList\" style=\"flex:1;overflow-y:auto;-webkit-overflow-scrolling:touch\"><div style=\"padding:40px;text-align:center;color:var(--text3);font-size:13px\">\ubd88\ub7ec\uc624\ub294 \uc911...</div></div>';\n  loadFunBoardList();\n};\nasync function loadFunBoardList() {\n  const list = document.getElementById('funBoardList');\n  if (!list) return;\n  try {\n    const { db, collection, getDocs, query, orderBy, limit } = window._mapDB;\n    const snap = await getDocs(query(collection(db,'funboard'), orderBy('createdAt','desc'), limit(50)));\n    const posts = snap.docs.map(d => ({ id:d.id, ...d.data() }));\n    if (!posts.length) { list.innerHTML = '<div style=\"padding:60px;text-align:center;color:var(--text3);font-size:13px\">\ud55c\ub958 \uc6c3\uae34 \uc601\uc0c1\uc744 \uacf5\uc720\ud574 \uc8fc\uc138\uc694!<br>\uc720\ud29c\ube0c \uc22b\uce20 \ub9c1\ud06c\ub97c \ub123\uc73c\uba74 \uc790\ub3d9\uc73c\ub85c \ubcf4\uc5ec\uc9d1\ub2c8\ub2e4</div>'; return; }\n    const escF = v => String(v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');\n    const ytReF = /https?:\\/\\/(?:www\\.|m\\.)?(?:youtube\\.com\\/(?:watch\\?v=|embed\\/|shorts\\/)|youtu\\.be\\/[\\w-]{11}|youtu\\.be\\/)([\\w-]{11})[^\\s]*/g;\n    list.innerHTML = posts.map(p => {\n      const isAdmin=window.isAdmin&&window.isAdmin(), isOwner=window.currentUser&&window.currentUser.uid===p.uid, canDel=isAdmin||isOwner;\n      const bodyRaw=p.body||'', ytIds=[];\n      let bodyTxt=bodyRaw.replace(ytReF,(m,id)=>{ytIds.push(id);return '';}).trim();\n      const ytHtml=ytIds.map(id=>'<div style=\"position:relative;padding-bottom:177.78%;height:0;overflow:hidden;border-radius:10px;margin:8px 0\"><iframe src=\"https://www.youtube.com/embed/'+id+'\" style=\"position:absolute;top:0;left:0;width:100%;height:100%;border:0\" allowfullscreen loading=\"lazy\"></iframe></div>').join('');\n      const preview=bodyTxt.length>80?escF(bodyTxt.slice(0,80))+'...':escF(bodyTxt);\n      return '<div style=\"padding:14px 16px;border-bottom:1px solid var(--border)\">'+\n        '<div style=\"font-size:14px;font-weight:700;margin-bottom:4px\">'+escF(p.title||'')+'</div>'+\n        (bodyTxt?'<div class=\"fun-preview\" style=\"font-size:12px;color:var(--text2);white-space:pre-wrap;margin-bottom:4px\">'+preview+'</div>':'')+\n        (bodyTxt&&bodyTxt.length>80?'<div class=\"fun-full\" style=\"font-size:12px;color:var(--text2);white-space:pre-wrap;margin-bottom:4px;display:none\">'+escF(bodyTxt)+'</div>':'')+\n        ytHtml+\n        '<div style=\"display:flex;align-items:center;justify-content:space-between;margin-top:6px\">'+\n          '<div style=\"font-size:11px;color:var(--text3)\">'+escF(p.userName||'\uc775\uba85')+'</div>'+\n          '<div style=\"display:flex;gap:6px\">'+\n            (bodyTxt.length>80?'<button onclick=\"funToggle(this)\" style=\"font-size:11px;color:var(--gold);border:none;background:none;cursor:pointer;padding:0\">\ub354 \ubcf4\uae30</button>':'')+\n            (canDel?'<button onclick=\"deleteFunPost(\\''+p.id+'\\')\" style=\"font-size:11px;color:#ef4444;border:none;background:none;cursor:pointer;padding:0\">\uc0ad\uc81c</button>':'')+\n          '</div>'+\n        '</div>'+\n      '</div>';\n    }).join('');\n  } catch(e) { console.error(e); }\n}\nwindow.openFunBoardWrite = function() {\n  if (!window.currentUser) { showToast('\U0001f512 \ub85c\uadf8\uc778\uc774 \ud544\uc694\ud574\uc694'); return; }\n  const old = document.getElementById('funBoardWrite');\n  if (old) old.remove();\n  const w = document.createElement('div');\n  w.id = 'funBoardWrite';\n  w.style.cssText = 'position:fixed;inset:0;z-index:10000;display:flex;justify-content:center;background:rgba(0,0,0,0.3)';\n  const wi = document.createElement('div');\n  wi.style.cssText = 'background:var(--bg);display:flex;flex-direction:column;width:100%;max-width:620px;height:100%;';\n  w.appendChild(wi);\n  document.body.appendChild(w);\n  wi.innerHTML =\n    '<div style=\"display:flex;align-items:center;gap:10px;padding:14px 16px;border-bottom:1px solid var(--border)\">' +\n      '<button onclick=\"document.getElementById(\\'funBoardWrite\\').remove()\" style=\"background:var(--bg2);border:1px solid var(--border);border-radius:9px;width:36px;height:36px;font-size:18px;cursor:pointer\">\u2190</button>' +\n      '<div style=\"font-size:16px;font-weight:800;flex:1\">\uc6c3\uc9c4 \uc601\uc0c1 \uacf5\uc720</div>' +\n      '<button onclick=\"submitFunPost()\" style=\"background:var(--gold);color:#fff;border:none;border-radius:9px;padding:8px 16px;font-size:13px;font-weight:700;cursor:pointer\">\ub4f1\ub85d</button>' +\n    '</div>' +\n    '<div style=\"flex:1;overflow-y:auto;padding:16px;display:flex;flex-direction:column;gap:10px\">' +\n      '<input id=\"funTitle\" placeholder=\"\uc81c\ubaa9 (\uc120\ud0dd\uc0ac\ud56d)\" style=\"width:100%;padding:12px;border:1px solid var(--border);border-radius:11px;font-size:15px;font-weight:700;font-family:inherit;background:var(--bg2);color:var(--text)\">' +\n      '<textarea id=\"funBody\" placeholder=\"\uc720\ud29c\ube0c \uc22b\uce20 \ub9c1\ud06c\ub97c \ub123\uc73c\uba74 \uc790\ub3d9\uc73c\ub85c \uc601\uc0c1\uc774 \ubcf4\uc5ec\uc9d1\ub2c8\ub2e4!\" style=\"width:100%;flex:1;min-height:200px;padding:12px;border:1px solid var(--border);border-radius:11px;font-size:14px;font-family:inherit;resize:none;background:var(--bg2);color:var(--text)\"></textarea>' +\n    '</div>';\n};\nwindow.submitFunPost = async function() {\n  const body = document.getElementById('funBody').value.trim();\n  const title = document.getElementById('funTitle').value.trim();\n  if (!body) { showToast('\ub9c1\ud06c\ub97c \uc785\ub825\ud574\uc8fc\uc138\uc694'); return; }\n  try {\n    const { db, collection, addDoc, serverTimestamp } = window._mapDB;\n    await addDoc(collection(db,'funboard'), { title, body,\n      uid: window.currentUser.uid, userName: window.currentUser.displayName||'\uc775\uba85',\n      createdAt: serverTimestamp() });\n    document.getElementById('funBoardWrite').remove();\n    showToast('\u2705 \ub4f1\ub85d\ub418\uc5c8\uc5b4\uc694');\n    loadFunBoardList();\n  } catch(e) { showToast('\uc2e4\ud328:'+(e.message||e)); }\n};\nwindow.funToggle = function(btn) {\n  const card = btn.closest ? btn.closest('[style*=\"border-bottom:1px\"]') : btn.parentElement.parentElement.parentElement;\n  const pre = card ? card.querySelector('.fun-preview') : null;\n  const full = card ? card.querySelector('.fun-full') : null;\n  if (!pre||!full) return;\n  const isOpen = full.style.display!=='none';\n  pre.style.display = isOpen?'':'none';\n  full.style.display = isOpen?'none':'';\n  btn.textContent = isOpen?'\ub354 \ubcf4\uae30':'\uc811\uae30';\n};\nwindow.deleteFunPost = async function(pid) {\n  if (!confirm('\uc0ad\uc81c\ud558\uc2dc\uaca0\uc2b5\ub2c8\uae4c?')) return;\n  try {\n    const {db,doc,deleteDoc}=window._mapDB;\n    await deleteDoc(doc(db,'funboard',pid));\n    showToast('\uc0ad\uc81c\ub418\uc5c8\uc5b4\uc694');\n    loadFunBoardList();\n  } catch(e){showToast('\uc2e4\ud328:'+e.message);}\n};\n"
    s=s.replace(anchor,func+anchor,1); changes.append("func")
else:
    changes.append("func skip")

# 3) 버전
if "const VERSION = 'map v1.9.16';" in s:
    s=s.replace("const VERSION = 'map v1.9.16';","const VERSION = 'map v1.9.17';")
    changes.append("v1.9.17")

io.open(PATH,"w",encoding="utf-8",newline="").write(s)
print("OK -", ", ".join(changes))
